{"command":"# Let's check what characters are around the warning
$content = [System.IO.File]::ReadAllText("$env:TEMP\tsp-output.txt")
$idx = $content.IndexOf("warning")
if ($idx -ge 0) {
    $snippet = $content.Substring([Math]::Max(0, $idx-5), 100)
    $bytes = [System.Text.Encoding]::UTF8.GetBytes($snippet)
    ($bytes | ForEach-Object { "{0:X2}" -f $_ }) -join ' '
}","description":"Check bytes around warning keyword"}

