$errors = ($clean -split "`n") | Where-Object { $_ -match ' - error ' }
$warnings = ($clean -split "`n") | Where-Object { $_ -match ' - warning ' }
"Errors: $($errors.Count)"
"Warnings: $($warnings.Count)"
if ($errors.Count -gt 0) { $errors | Select-Object -First 5 }
if ($warnings.Count -gt 0) { $warnings | Select-Object -First 5 }

